# Math utility module - provides mathematical helpers

@static
PI: float = 3.14159

@static
E: float = 2.71828

def square(n: int) -> int:
    return n * n

def average(values: list[int]) -> float:
    total: int = 0
    for v in values:
        total += v
    return total / len(values)

def clamp(value: int, min_val: int, max_val: int) -> int:
    if value < min_val:
        return min_val
    if value > max_val:
        return max_val
    return value

def factorial(n: int) -> int:
    if n <= 1:
        return 1
    return n * factorial(n - 1)
